#!/usr/bin/env node
// Generates packages/types/src/skills/content.generated.ts from the .md files
// under packages/types/src/skills/screenshotsmcp/. This is the single source of
// truth for the core ScreenshotsMCP skill. The generated file is committed so
// `tsc` builds work without running this script first; a `prebuild` hook keeps
// it in sync, and `verify-skills.mjs` catches drift in CI.

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(__dirname, "..", "..", "..");
const skillRoot = join(__dirname, "..", "src", "skills", "screenshotsmcp");
const outFile = join(__dirname, "..", "src", "skills", "content.generated.ts");

const files = {
  CORE_SKILL_CONTENT: join(skillRoot, "SKILL.md"),
  CORE_SITEWIDE_PERFORMANCE_WORKFLOW_CONTENT: join(skillRoot, "workflows", "sitewide-performance-audit", "WORKFLOW.md"),
  CORE_WORKOS_AUTHKIT_WORKFLOW_CONTENT: join(skillRoot, "workflows", "workos-authkit-signup", "WORKFLOW.md"),
  CORE_SEO_AUDIT_WORKFLOW_CONTENT: join(skillRoot, "workflows", "seo-audit", "WORKFLOW.md"),
  CORE_UX_ACCESSIBILITY_AUDIT_WORKFLOW_CONTENT: join(skillRoot, "workflows", "ux-accessibility-audit", "WORKFLOW.md"),
  CORE_RESPONSIVE_AUDIT_WORKFLOW_CONTENT: join(skillRoot, "workflows", "responsive-audit", "WORKFLOW.md"),
};

const relativeSources = Object.fromEntries(
  Object.entries(files).map(([name, abs]) => [name, abs.slice(repoRoot.length + 1).replaceAll("\\", "/")]),
);

const header = `// DO NOT EDIT. Auto-generated by packages/types/scripts/generate-skill-content.mjs
// Sources:
${Object.entries(relativeSources).map(([name, rel]) => `//   ${name} <- ${rel}`).join("\n")}
`;

const exports = Object.entries(files)
  .map(([name, path]) => {
    const raw = readFileSync(path, "utf8");
    const normalized = raw.replace(/\r\n/g, "\n");
    return `export const ${name}: string = ${JSON.stringify(normalized)};`;
  })
  .join("\n\n");

const output = `${header}\n${exports}\n`;

mkdirSync(dirname(outFile), { recursive: true });
writeFileSync(outFile, output, "utf8");
console.log(`Generated ${outFile}`);
